actions.pre_process_function:
// Pre-process function for symmetric text embedding
// Handle both direct API calls and OpenSearch text embedding processor
if (params.texts != null) {
  // Direct API call format
  String textsJson = params.texts.toString();
  return '{"parameters":{"texts":' + textsJson + '}}';
}
else if (params.inputText != null) {
  // OpenSearch text embedding processor format
  String inputText = params.inputText;
  return '{"parameters":{"texts":["' + inputText + '"]}}';  
}
else {
  // Fallback: try to extract text from any string parameter
  for (String key : params.keySet()) {
    Object value = params.get(key);
    if (value instanceof String && ((String)value).length() > 0) {
      return '{"parameters":{"texts":["' + value + '"]}}';
    }
  }
  throw new IllegalArgumentException("No text input found in parameters: " + params.keySet());
}
